{
  "grammar": [
    {
      "pattern": "如果...的話，就...",
      "structure": ["如果", "condition", "的話", "，", "就", "result"],
      "explanation_en": "This structure is used to express a conditional relationship, meaning 'if...then...'. It is a key pattern for discussing hypothetical situations and their consequences.",
      "title": "Conditional Sentences with 如果...的話",
      "meaning": "If (condition), then (result).",
      "when_to_use": [
        "When discussing possible future events or plans",
        "When giving advice or suggestions based on a condition",
        "When explaining cause and effect in a hypothetical scenario"
      ],
      "when_not_to_use": [
        "Do not use for factual or always-true statements (use 就 alone or other patterns)",
        "Avoid using with 了 for completed actions in the condition clause"
      ],
      "pragmatic_notes": "In Taiwan, this pattern is very common in daily conversation. The 的話 part is often omitted in casual speech, but including it makes the condition more polite and tentative.",
      "word_order_notes": "The condition clause comes first, followed by 的話 (optional), then a comma, and finally the result clause with 就.",
      "english_contrast": "English uses 'if' at the beginning or middle; Chinese always places the condition first.",
      "korean_contrast": "Korean uses '-(으)면' at the end of the condition clause; Chinese uses 如果 at the beginning.",
      "negative_examples": [
        {
          "text": "如果我去，就我買咖啡。",
          "error": "The subject should be placed before 就, not after. Correct: 如果我去，我就買咖啡。"
        }
      ],
      "incorrect_examples": [
        {
          "text": "如果天氣好，我們就去公園。",
          "error": "This sentence is actually correct. The error is that the learner might think 的話 is required, but it's optional."
        }
      ],
      "transformation_drills": [
        "Change '如果明天下雨，我們就不去公園。' to use 的話.",
        "Change '如果你有空，就來找我。' to a negative condition."
      ],
      "production_drills": [
        "Make a sentence about going to a restaurant if you are hungry.",
        "Make a sentence about buying a drink if it is hot."
      ],
      "common_error_patterns": [
        "Forgetting to place the subject before 就",
        "Using 了 in the condition clause incorrectly"
      ],
      "repair_feedback": {
        "word_order": "Remember: subject + 如果 + condition + 的話 + 就 + subject + result.",
        "politeness": "Adding 的話 makes the condition sound more polite.",
        "vocabulary": "Use 如果 for hypotheticals; for real conditions, you can use 要是."
      }
    },
    {
      "pattern": "雖然...，但是...",
      "structure": ["雖然", "clause 1", "，", "但是", "clause 2"],
      "explanation_en": "This structure expresses contrast or concession, meaning 'although...but...'. It is used to acknowledge a fact while presenting an opposing or unexpected point.",
      "title": "Contrast with 雖然...但是",
      "meaning": "Although (clause 1), but (clause 2).",
      "when_to_use": [
        "When you want to show a contrast between two ideas",
        "When conceding a point but emphasizing another",
        "In discussions, debates, or giving balanced opinions"
      ],
      "when_not_to_use": [
        "Do not use for simple addition of ideas (use 而且 instead)",
        "Avoid using 但是 alone without 雖然 if the contrast is strong"
      ],
      "pragmatic_notes": "In Taiwan, 雖然...但是 is very common in both spoken and written Chinese. It is polite and shows careful reasoning. Sometimes 可是 or 不過 is used instead of 但是 in casual speech.",
      "word_order_notes": "雖然 introduces the first clause, followed by a comma, then 但是 introduces the second clause. The subject can be repeated or omitted if the same.",
      "english_contrast": "English uses 'although' and 'but' together, but Chinese requires both 雖然 and 但是 for full contrast.",
      "korean_contrast": "Korean uses '-(지)만' or '-지만' at the end of the first clause; Chinese uses 雖然 at the beginning.",
      "negative_examples": [
        {
          "text": "雖然他很有錢，他很不高興。",
          "error": "Missing 但是 or 可是. Correct: 雖然他很有錢，但是他很不高興。"
        }
      ],
      "incorrect_examples": [
        {
          "text": "雖然天氣很冷，但是我不穿外套。",
          "error": "This sentence is correct. The error is that the learner might think 但是 is optional, but it is required for contrast."
        }
      ],
      "transformation_drills": [
        "Change '雖然這家餐廳很貴，但是很好吃。' to use 可是 instead of 但是.",
        "Change '雖然他沒有錢，但是他很快樂。' to a negative form."
      ],
      "production_drills": [
        "Make a sentence about a food that is expensive but delicious.",
        "Make a sentence about a place that is far but beautiful."
      ],
      "common_error_patterns": [
        "Omitting 但是 when the contrast is strong",
        "Using 雖然 and 但是 with the same subject incorrectly"
      ],
      "repair_feedback": {
        "word_order": "雖然 + clause 1 + 但是 + clause 2. The subject can be in either clause.",
        "politeness": "Using 雖然...但是 shows careful reasoning and is polite.",
        "vocabulary": "Use 雖然 for concession; for simple contrast, 可是 is more casual."
      }
    },
    {
      "pattern": "因為...，所以...",
      "structure": ["因為", "reason", "，", "所以", "result"],
      "explanation_en": "This structure expresses cause and effect, meaning 'because...so...'. It is used to explain reasons and their consequences.",
      "title": "Cause and Effect with 因為...所以",
      "meaning": "Because (reason), so (result).",
      "when_to_use": [
        "When explaining why something happened",
        "When giving reasons for decisions or actions",
        "In both formal and informal contexts"
      ],
      "when_not_to_use": [
        "Do not use for unrelated ideas",
        "Avoid using 所以 without 因為 if the cause is clear from context"
      ],
      "pragmatic_notes": "In Taiwan, 因為...所以 is very common. In casual speech, 所以 is often used alone if the reason is obvious. It is polite to give a reason before stating the result.",
      "word_order_notes": "因為 introduces the reason clause, followed by a comma, then 所以 introduces the result clause. The subject can be placed before or after 因為.",
      "english_contrast": "English uses 'because' and 'so' separately; Chinese requires both for a full cause-effect structure.",
      "korean_contrast": "Korean uses '-(기) 때문에' or '-(어)서' at the end of the reason clause; Chinese uses 因為 at the beginning.",
      "negative_examples": [
        {
          "text": "因為我餓，所以我吃麵。",
          "error": "This sentence is correct. The error is that the learner might think 所以 is optional, but it is required for clarity."
        }
      ],
      "incorrect_examples": [
        {
          "text": "因為下雨，所以我不去公園。",
          "error": "This sentence is correct. The error is that the learner might forget the comma, but it is optional in writing."
        }
      ],
      "transformation_drills": [
        "Change '因為他很忙，所以他沒來。' to use 所以 alone.",
        "Change '因為天氣熱，所以我們喝冰水。' to a negative reason."
      ],
      "production_drills": [
        "Make a sentence about why you are late.",
        "Make a sentence about why you like a certain food."
      ],
      "common_error_patterns": [
        "Omitting 所以 when the result is not obvious",
        "Using 因為 and 所以 with the same subject incorrectly"
      ],
      "repair_feedback": {
        "word_order": "因為 + reason + 所以 + result. The subject can be in either clause.",
        "politeness": "Giving a reason first is polite and clear.",
        "vocabulary": "Use 因為 for cause; for informal speech, 因為 can be shortened to 因."
      }
    }
  ]
}
